"use client";

import React, { useState, useEffect } from "react";
import { client } from "@/utils/helper";
import { useParams } from "next/navigation";

export default function ProductDetails() {
  const [data, setData] = useState(null);
  const params = useParams();
  const id = params.id;
  useEffect(() => {
    if (!id) return; // ✅ FIXED

    client
      .get(`product/${id}`)
      .then((response) => {
        const formdata = response.data.data;
        console.log( "shfshfhskfhs",formdata.images);
        setData(formdata);
      })
      .catch((error) => {
        console.log(error,"error is coming");
      });
  }, [id]);

  return (
    <div className="p-8 bg-gray-50 min-h-screen">
      <div className="max-w-6xl mx-auto bg-white rounded-2xl shadow-lg p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Left - Images */}
        <div>
          <div className="rounded-xl overflow-hidden border mb-4">
            <img
              src={`http://localhost:5000/product/${data?.thumbnail}`}
              alt={data?.name}
              className="w-full h-80 object-cover"
            />
          </div>

          {/* Other Images
          <div className="grid grid-cols-4 gap-3">
            {data?.images?.map((img, index) => (
              <img
                key={index}
                src={`http://localhost:5000/product/${img}`}
                className="h-20 w-full object-cover rounded-lg border"
                alt=""
              />
            ))}
          </div> */}
        </div>

        {/* Right - Details */}
        <div className="flex flex-col gap-5">
          <h1 className="text-2xl font-semibold text-gray-800">
            {data?.name}
          </h1>

          {/* Price Section */}
          <div className="flex items-center gap-4">
            <span className="text-gray-400 line-through text-lg">
              ₹{data?.original_price}
            </span>
            <span className="text-2xl font-bold text-green-600">
              ₹{data?.final_price}
            </span>
            <span className="text-sm bg-green-100 text-green-700 px-2 py-1 rounded">
              {data?.discount_percentage}% OFF
            </span>
          </div>

          {/* Category & Brand */}
          <div className="flex gap-3">
            <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-sm">
              {data?.categoryId?.name}
            </span>
            <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-sm">
              {data?.brandId?.name}
            </span>
          </div>

          {/* Status Section */}
          <div className="flex flex-wrap gap-3">
            <Status value={data?.status} type="product" id={data?._id} feild="status" />
            <Status value={data?.stock} type="product" id={data?._id} feild="stock" />
            {/* Add more statuses dynamically
            {product.otherStatus?.map((s, i) => (
              <Status key={i} value={s.value} type="product" id={product._id} feild={s.key} />
            ))} */}
          </div>

          {/* Description */}
          <div>
            <h2 className="text-lg font-semibold text-gray-700 mb-2">
              Description
            </h2>
            <p className="text-gray-600 text-sm leading-relaxed">
              {data?.description}
            </p>
          </div>

          {/* Extra Info */}
          <div className="grid grid-cols-2 gap-4 text-sm">
            <div className="bg-gray-50 p-3 rounded-lg">
              <p className="text-gray-500">Product ID</p>
              <p className="font-medium text-gray-800">{data._id}</p>
            </div>

            <div className="bg-gray-50 p-3 rounded-lg">
              <p className="text-gray-500">Slug</p>
              <p className="font-medium text-gray-800">{data.slug}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
